function setDefault$Voucher$Tax(f) {
  var g = f.getItem("d32")._controlBehavior, z = f.getItem("r30")._controlBehavior, row = 1;
  if (z._rowCount > 1) {
    setDefaultTaxItems(z, z._rowCount, ['ma_tc', 'ma_thue', 'thue_suat', 'tk_thue_no', 'tk_cn', 'ma_mau_ct'], [z._taxProperty, z._taxCode, z._taxRate, z._taxAccount, z._taxType, z._voucherTemplate]);
    return;
  }
  if ((z._rowCount > 0) && (z._getItemValue(row, z._getColumnOrder('so_ct0')) == '')) {
    setDefaultTaxItems(z, row, ['mau_bc', 'ma_tc', 'ma_thue', 'thue_suat', 'tk_thue_no', 'tk_cn', 'ma_mau_ct'],
      ['3', z._taxProperty, z._taxCode, z._taxRate, z._taxAccount, z._taxType, z._voucherTemplate]);
    &ScriptTaxGridDetailAmountDefault;
    z.assignExpression(row - 1, z.$a.z_t_thue);
    z.assignExpression(row - 1, z.$a.z_t_thue_nt);
    z.validExpression(null, null, [z.$a.t_thue2_nt, z.$a.t_thue2], [z.$a.t_thue_nt, z.$a.t_thue, z.$a.t_tt_nt, z.$a.t_tt]);
    var max = g.max('tien') + 1;
    if (max > 0) z._getItem(1, z._getColumnOrder('ten_vt')).value = g._getItem(max, g._getColumnOrder('dien_giai')).value;
  }
}





